<table id="archivebox" role="presentation" class="{{talk other|tmbox tmbox-notice|ombox ombox-notice|demospace={{{demospace|}}}}} {{#ifeq:{{{banner|{{{large}}}}}}|yes||mbox-small}} {{#ifeq:{{{collapsed}}}|yes|mw-collapsible mw-collapsed|{{#ifeq:{{{collapsible}}}|yes|mw-collapsible}}}} {{{class|}}}" style="text-align: center; padding: 1em; {{#if:{{{box-width|}}}|width:{{{box-width}}};}} {{#ifeq:{{{banner|{{{large}}}}}}|yes|min-width:80%;}} {{{style|}}}">
<tr>
{{#ifeq:{{{banner|{{{large}}}}}}|yes
|<!-- Banner style: image in a rowspan cell (if present) -->
{{#ifeq:{{{image|}}}|none||
<td rowspan="{{#expr:1+{{#ifeq:{{{search}}}|no|0|1}}+{{#if:{{{list|{{{1|}}}}}}|1|0}}+{{#if:{{{age|}}}{{{target|}}}|1|0}}}}" class="mbox-image" style="width:52px;">
{{#invoke:InfoboxImage|InfoboxImage|alt={{{alt|}}}|link={{{link|}}}|image={{{image|Replacement filing cabinet.svg}}}|size={{{image-size|}}}|sizedefault=40px}}
</td>
}}
|<!-- Box style: header row, with image (if present) -->
<td style="padding:0.6em 0 0.25em;">
<div style="{{#ifeq:{{{image|}}}|none||width:100%; overflow:hidden;}}">{{#ifeq:{{{image|}}}|none||{{#invoke:InfoboxImage|InfoboxImage|alt={{{alt|}}}|link={{{link|}}}|image={{{image|Replacement filing cabinet.svg}}}|size={{{image-size|}}}|sizedefault=40px}}<br>}}<b>{{{title|Archives}}}</b></div>
</tr><tr>
}}
<td class="plainlinks {{#ifeq:{{{banner|{{{large}}}}}}|yes|mbox-text}}">
{{#ifeq:{{{banner|{{{large}}}}}}|yes|{{{title|Archives}}}&#58;&#32;}}{{#switch:{{#if:{{{list|}}}|no|{{{auto|{{#if:{{{1|}}}|no}}}}}}}
|#default={{#ifeq:{{{index|}}}|none||{{#ifexist:{{#rel2abs:./{{{index|Archive index}}}}}|[[{{#rel2abs:./{{{index|Archive index}}}}}|Index]]&#32;|{{#ifexist:User:ClueBot III/Master Detailed Indices/{{FULLPAGENAME}}|[[User:ClueBot III/Master Detailed Indices/{{FULLPAGENAME}}|Index]]&#32;}}}}
 }}{{#ifexist:{{#rel2abs:{{#if:{{{archivelist|}}}|{{{archivelist}}}|./archivelist}}}}
  |<div style="text-align:left;">{{ {{#rel2abs:{{{archivelist|./archivelist}}}}} }}</div>
  |{{Archive list
   |{{#if:{{{root|}}}|root|DISABLE1}}={{{root}}}
   |{{#ifeq:{{{banner|{{{large}}}}}}|yes|DISABLE2|auto}}={{{auto|long}}}
   |nobr={{#ifeq:{{{banner|{{{large}}}}}}|yes|yes|no}}
   |{{#if:{{{prefix|}}}|prefix|DISABLE3}}={{{prefix|}}}
   |{{#if:{{{start|}}}|start|DISABLE4}}={{{start|}}}
  }}
 }}
|no=<!--no output-->}}{{#if:{{{list|{{{1|}}}}}}
 |</td></tr><tr><td class="plainlinks" style="padding:0px 10px; {{#ifeq:{{{banner|{{{large}}}}}}|yes||text-align:left;}}">
{{{list|{{{1|}}}}}}<!--Parameters MUST be on newline or some wikimarkup will fail-->}}
</td><!--List/1 MUST be separate from all other tags-->
</tr>{{#ifeq:{{{search}}}|no||<tr><td style="padding-bottom:11px">{{#tag:inputbox|
bgcolor=transparent
type=fulltext
prefix={{if empty|{{{searchprefix|}}}|{{{root|}}}|{{FULLPAGENAME}}/}}
break={{#ifeq:{{{banner|{{{large}}}}}}|yes|{{{search-break|no}}}|{{{search-break|yes}}}}}
width={{#ifeq:{{{banner|{{{large}}}}}}|yes||{{#if:{{{search-width|}}}|{{{search-width}}}|22}}}}
searchbuttonlabel={{{search-button-label|{{{button-label|Search archives}}}}}}
}}
</td></tr>
}}{{#if:{{{age|}}}{{{archive_age|}}}{{{target|}}}{{Th/abp|bot|{{{root|{{FULLPAGENAME}}}}}}}|<tr><td {{#ifeq:{{{banner|{{{large}}}}}}|yes|colspan=2}} style="padding:0px 10px; font-size:11.9px; {{#ifeq:{{{banner|{{{large}}}}}}|yes|text-align:center;}}">
----
